pauli_stabilizers = [stim.PauliString(s) for s in stabilizers]

p23 = pauli_stabilizers[23]
p59 = pauli_stabilizers[59]

print(f"P23 length: {len(p23)}")
print(f"P59 length: {len(p59)}")

def print_indices(p, label):
    print(f"{label} indices:")
    for i in range(len(p)):
        gate = p[i]
        if gate != 0: # 0 is I, 1 is X, 2 is Y, 3 is Z
            print(f"  {i}: {gate}")

print_indices(p23, "P23")
print_indices(p59, "P59")

print(f"Commutes? {p23.commutes(p59)}")

